import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion, useReducedMotion } from 'framer-motion';
import PostCard from '../components/PostCard';
import '../styles/SubjectPage.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5002';

const listVariants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.06 } },
};
const itemVariant = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.35, ease: 'easeOut' } },
};

function SubjectPage({ darkMode, setDarkMode }) {
  const { id } = useParams();
  const navigate = useNavigate();
  const [subject, setSubject] = useState(null);
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({ semester: '', grade: '' });
  const [search, setSearch] = useState('');
  const [sortOrder, setSortOrder] = useState('desc');
  const reduceMotion = useReducedMotion();

  const fetchAll = useCallback(async () => {
    try {
      const [subjectRes, postsRes] = await Promise.all([
        fetch(`${API_URL}/api/subjects/${id}`),
        fetch(`${API_URL}/api/posts/subject/${id}`),
      ]);
      setSubject(await subjectRes.json());
      setPosts(await postsRes.json());
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const semesters = useMemo(() => [...new Set(posts.map(p => p.semester).filter(Boolean))], [posts]);
  const grades    = useMemo(() => [...new Set(posts.map(p => p.grade).filter(Boolean))], [posts]);

  const filtered = useMemo(() => {
    let list = posts;
    if (filters.semester) list = list.filter(p => p.semester === filters.semester);
    if (filters.grade)    list = list.filter(p => p.grade    === filters.grade);
    if (search.trim())    list = list.filter(p =>
      p.title?.toLowerCase().includes(search.toLowerCase()) ||
      p.description?.toLowerCase().includes(search.toLowerCase())
    );
    list = [...list].sort((a, b) => {
      const diff = new Date(a.date_created) - new Date(b.date_created);
      return sortOrder === 'asc' ? diff : -diff;
    });
    return list;
  }, [posts, filters, search, sortOrder]);

  const animateList = !reduceMotion && filtered.length <= 12;

  if (loading) return <div className="spinner" style={{ marginTop: 80 }} />;
  if (!subject) return <div className="sp-not-found">Subject not found</div>;

  return (
    <div className="sp-page">
      {/* Header */}
      <header className="sp-header">
        <div className="container sp-header-inner">
          <button className="btn btn-ghost btn-sm sp-back" onClick={() => navigate('/')}>
            ← Back
          </button>
          <div className="sp-subject-info">
            <h1 className="sp-subject-name">{subject.name}</h1>
            {subject.description && <p className="sp-subject-desc">{subject.description}</p>}
          </div>

        </div>
      </header>

      <div className="container sp-body">
        {/* Sidebar filters */}
        <aside className="sp-sidebar">
          <div className="sp-filter-group">
            <label htmlFor="sp-search">🔍 Search</label>
            <input
              className="sp-control"
              id="sp-search"
              type="text"
              placeholder="Search posts…"
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
          </div>

          <div className="sp-filter-group">
            <label>Semester</label>
            <select className="sp-control" value={filters.semester} onChange={e => setFilters(f => ({ ...f, semester: e.target.value }))}>
              <option value="">All semesters</option>
              {semesters.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="sp-filter-group">
            <label>Grade</label>
            <select className="sp-control" value={filters.grade} onChange={e => setFilters(f => ({ ...f, grade: e.target.value }))}>
              <option value="">All grades</option>
              {grades.map(g => <option key={g} value={g}>{g}</option>)}
            </select>
          </div>

          <div className="sp-filter-group">
            <label>Sort by date</label>
            <select className="sp-control" value={sortOrder} onChange={e => setSortOrder(e.target.value)}>
              <option value="desc">Newest first</option>
              <option value="asc">Oldest first</option>
            </select>
          </div>

          {(filters.semester || filters.grade || search) && (
            <button
              className="btn btn-ghost btn-sm sp-clear"
              onClick={() => { setFilters({ semester: '', grade: '' }); setSearch(''); }}
            >
              ✕ Clear filters
            </button>
          )}

          <div className="sp-count">
            {filtered.length} post{filtered.length !== 1 ? 's' : ''}
          </div>
        </aside>

        {/* Posts */}
        <main className="sp-posts">
          {filtered.length === 0 ? (
            <p className="sp-empty">No posts match your filters.</p>
          ) : animateList ? (
            <motion.div
              className="sp-posts-list"
              variants={listVariants}
              initial="hidden"
              animate="visible"
            >
              {filtered.map(post => (
                <motion.div key={post._id} variants={itemVariant}>
                  <PostCard post={post} />
                </motion.div>
              ))}
            </motion.div>
          ) : (
            <div className="sp-posts-list">
              {filtered.map(post => (
                <div key={post._id}>
                  <PostCard post={post} />
                </div>
              ))}
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

export default SubjectPage;
